def descriptor(rA, rB, rX, nA, nB, nX):
    # New descriptor based on the ratio of ionic radii scaled by their oxidation states
    size_ratio = (rA / rX) / (rB / rX)
    charge_ratio = nA / nB
    # Combine size ratio and charge ratio to account for size compatibility modulated by electrostatic considerations
    return abs(size_ratio - charge_ratio) + abs(nA + nX) / (abs(nB + nX) + 1e-6)

def descriptor(rA, rB, rX, nA, nB, nX):
    # New descriptor: measures mismatch of ionic radii scaled by the geometric mean of oxidation states
    import math
    size_mismatch = abs(rA - rX) + abs(rB - rX)
    oxidation_scale = math.sqrt(abs(nA) * abs(nB))
    return size_mismatch / (oxidation_scale + 1e-8)

