def descriptor(rA, rB, rX, nA, nB, nX):
    # New descriptor: combines ionic radius difference with oxidation state disparity weighted by ionic radii
    size_disparity = abs(rA - rB) + abs(rX - (rA + rB)/2)
    valence_disparity = abs(nA - nB) + abs(nX - (nA + nB)/2)
    # Normalize by sum of radii and absolute oxidation states to balance physical scales
    return (size_disparity / (rA + rB + rX)) + (valence_disparity / (abs(nA) + abs(nB) + abs(nX)))

def descriptor(rA, rB, rX, nA, nB, nX):
    # New descriptor: combines ionic size mismatch with electrostatic and valence difference
    size_diff = abs(rA - rX) + abs(rB - rX)
    valence_diff = abs(nA - nX) + abs(nB - nX)
    combined_ratio = (abs(nA) + abs(nB)) / (abs(nX) + 1)
    return size_diff * valence_diff / (combined_ratio + 1e-6)

